using UnityEngine;

/// <summary>
/// Bolha de Ar — coleccionável subaquático que restaura o oxigênio de animais
/// terrestres que mergulham (<see cref="AnimalFormData.canDiveAsLand"/> = true).
///
/// Colocar em zonas subaquáticas onde o designer quer dar uma "recarga" ao
/// jogador antes que o oxigênio acabe.
///
/// Ao tocar:
/// - Se o <see cref="OxygenSystem"/> do player estiver activo (animal terrestre
///   submerso), restaura o oxigênio para o máximo da forma actual.
/// - Se o sistema não estiver activo (animal aquático nativo / fora de água),
///   a bolha ainda é recolhida mas sem efeito adicional (sem "desperdício" de
///   pickup — o pickupId garante que não aparece outra vez).
///
/// Sugestão de configuração:
/// - <b>Pickup Id</b>: único por instância (ex: "FlorestaSombria_BolhaAr_01").
/// - <b>Popup Text</b>: "Oxigênio restaurado!" (ou vazio — sem popup é mais
///   imersivo para uma bolha de ar automática).
/// - <b>Can Be Magnetized</b>: false recomendado (não deve ser atraído pelo Íman,
///   pois é mais natural ter de nadar até à bolha).
/// - <b>Autosave On Collect</b>: normalmente false (bolhas são auxiliares, não
///   progresso permanente — a não ser que sejam únicas/escondidas).
/// </summary>
public class BolhaDeArOxygenPickup : PickupBase
{
    public override PickupType Type => PickupType.BolhaDeAr;

    protected override void GrantReward()
    {
        OxygenSystem.Instance?.RestoreOxygen();
    }
}
